void AstInitArray::dumpInitList(std::ostream& str) const {
    int n = 0;
    const auto& mapr = map();
    for (const auto& itr : mapr) {
        if (n++ > 5) {
            str << " ...";
            break;
        }
        const string addr
            = (v3Global.opt.jsonIds() ? v3Global.ptrToId(itr.second) : nodeAddr(itr.second));
        str << " [" << itr.first << "]=" << addr;
    }
}
